     1→use parking_lot::Mutex;
     2→use portable_pty::{native_pty_system, CommandBuilder, PtySize};
     3→use serde::{Deserialize, Serialize};
     4→use std::collections::HashMap;
     5→use std::io::{Read, Write};
     6→use std::sync::Arc;
     7→use std::thread;
     8→use tauri::{AppHandle, Emitter, Runtime};
     9→use uuid::Uuid;
    10→
    11→/// Process info returned to frontend
    12→#[derive(Debug, Clone, Serialize, Deserialize)]
    13→pub struct ProcessInfo {
    14→    pub id: String,
    15→    pub cmd: String,
    16→    pub cwd: String,
    17→    pub rows: u16,
    18→    pub cols: u16,
    19→    pub running: bool,
    20→}
    21→
    22→/// Output event emitted to frontend
    23→#[derive(Debug, Clone, Serialize)]
    24→pub struct PtyOutput {
    25→    pub id: String,
    26→    pub data: String,
    27→}
    28→
    29→/// Exit event emitted to frontend
    30→#[derive(Debug, Clone, Serialize)]
    31→pub struct PtyExit {
    32→    pub id: String,
    33→    pub code: Option<i32>,
    34→}
    35→
    36→/// Internal process state
    37→struct PtyProcess {
    38→    info: ProcessInfo,
    39→    writer: Box<dyn Write + Send>,
    40→    master: Box<dyn portable_pty::MasterPty + Send>,
    41→    child: Box<dyn portable_pty::Child + Send + Sync>,
    42→}
    43→
    44→/// Global PTY manager
    45→pub struct PtyManager {
    46→    processes: Mutex<HashMap<String, PtyProcess>>,
    47→}
    48→
    49→impl Default for PtyManager {
    50→    fn default() -> Self {
    51→        Self::new()
    52→    }
    53→}
    54→
    55→impl PtyManager {
    56→    pub fn new() -> Self {
    57→        Self {
    58→            processes: Mutex::new(HashMap::new()),
    59→        }
    60→    }
    61→
    62→    /// Spawn a new PTY process
    63→    pub fn spawn<R: Runtime>(
    64→        &self,
    65→        app: &AppHandle<R>,
    66→        cmd: String,
    67→        args: Vec<String>,
    68→        cwd: String,
    69→        rows: u16,
    70→        cols: u16,
    71→    ) -> Result<ProcessInfo, String> {
    72→        let pty_system = native_pty_system();
    73→
    74→        let size = PtySize {
    75→            rows,
    76→            cols,
    77→            pixel_width: 0,
    78→            pixel_height: 0,
    79→        };
    80→
    81→        let pair = pty_system
    82→            .openpty(size)
    83→            .map_err(|e| format!("Failed to open pty: {}", e))?;
    84→
    85→        let mut cmd_builder = CommandBuilder::new(&cmd);
    86→        for arg in &args {
    87→            cmd_builder.arg(arg);
    88→        }
    89→        cmd_builder.cwd(&cwd);
    90→
    91→        let child = pair
    92→            .slave
    93→            .spawn_command(cmd_builder)
    94→            .map_err(|e| format!("Failed to spawn command: {}", e))?;
    95→
    96→        let id = Uuid::new_v4().to_string();
    97→
    98→        let info = ProcessInfo {
    99→            id: id.clone(),
   100→            cmd: cmd.clone(),
   101→            cwd: cwd.clone(),
   102→            rows,
   103→            cols,
   104→            running: true,
   105→        };
   106→
   107→        // Get reader for streaming output
   108→        let reader = pair
   109→            .master
   110→            .try_clone_reader()
   111→            .map_err(|e| format!("Failed to clone reader: {}", e))?;
   112→
   113→        // Get writer for sending input
   114→        let writer = pair
   115→            .master
   116→            .take_writer()
   117→            .map_err(|e| format!("Failed to take writer: {}", e))?;
   118→
   119→        // Store process
   120→        let process = PtyProcess {
   121→            info: info.clone(),
   122→            writer,
   123→            master: pair.master,
   124→            child,
   125→        };
   126→        self.processes.lock().insert(id.clone(), process);
   127→
   128→        // Spawn reader thread
   129→        let process_id = id.clone();
   130→        let app_handle = app.clone();
   131→        thread::spawn(move || {
   132→            Self::read_output(reader, process_id, app_handle);
   133→        });
   134→
   135→        Ok(info)
   136→    }
   137→
   138→    /// Read PTY output and emit events
   139→    fn read_output<R: Runtime>(
   140→        mut reader: Box<dyn Read + Send>,
   141→        process_id: String,
   142→        app: AppHandle<R>,
   143→    ) {
   144→        let mut buf = [0u8; 4096];
   145→        loop {
   146→            match reader.read(&mut buf) {
   147→                Ok(0) => {
   148→                    // EOF - process ended
   149→                    let _ = app.emit(
   150→                        "pty-exit",
   151→                        PtyExit {
   152→                            id: process_id.clone(),
   153→                            code: None,
   154→                        },
   155→                    );
   156→                    break;
   157→                }
   158→                Ok(n) => {
   159→                    // Convert to string (lossy for binary data)
   160→                    let data = String::from_utf8_lossy(&buf[..n]).to_string();
   161→                    let _ = app.emit(
   162→                        "pty-output",
   163→                        PtyOutput {
   164→                            id: process_id.clone(),
   165→                            data,
   166→                        },
   167→                    );
   168→                }
   169→                Err(e) => {
   170→                    eprintln!("PTY read error: {}", e);
   171→                    break;
