                        println!("No sessions found.");
                    } else {
                        println!("{:<26}  {:<20}  {}", "ID", "STARTED", "STATUS");
                        println!("{}", "-".repeat(60));
                        for session in &result.items {
                            let status = if session.ended_at.is_some() { "ended" } else { "active" };
                            println!(
                                "{:<26}  {:<20}  {}",
                                session.id,
                                truncate(&session.started_at.to_string(), 20),
                                status
                            );
                        }
                        if result.has_next {
                            println!();
                            println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
                        }
                    }
                }
            }
        }

        SessionCommands::Get { id } => {
            let session = db::get_session(&conn, &id)?
                .ok_or_else(|| CliError::NotFound(format!("Session {}", id)))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&session).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", session.id);
                }
                OutputFormat::Text => {
                    println!("ID:      {}", session.id);
                    println!("Summary: {}", session.summary.as_deref().unwrap_or("-"));
                    println!("Started: {}", session.started_at);
                    println!("Ended:   {}", session.ended_at.map(|d| d.to_string()).unwrap_or_else(|| "-".to_string()));

                    // Show progress entries
                    let progress = db::list_progress_for_session(&conn, &id)?;
                    if !progress.is_empty() {
                        println!();
                        println!("Progress ({}):", progress.len());
                        for entry in progress.iter().take(10) {
                            println!("  - {}", truncate(&entry.content, 60));
                        }
                        if progress.len() > 10 {
                            println!("  ... and {} more", progress.len() - 10);
                        }
                    }
                }
            }
        }
    }

    Ok(())
}

fn cmd_progress(project_dir: &PathBuf, command: ProgressCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        ProgressCommands::Add { content, session } => {
            // Use provided session or get current
            let session_id = match session {
                Some(id) => id,
                None => db::get_current_session(&conn)?
                    .ok_or(CliError::NoActiveSession)?
                    .id,
            };

            let progress = db::add_progress(&conn, &session_id, &content)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&progress).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", progress.id);
                }
                OutputFormat::Text => {
                    println!("Added progress: {}", progress.id);
                    println!("  Session: {}", session_id);
                    println!("  Content: {}", truncate(&content, 60));
                }
            }
        }

        ProgressCommands::List { session, limit, cursor } => {
            if let Some(session_id) = session {
                // List for specific session
                let entries = db::list_progress_for_session(&conn, &session_id)?;

                match format {
                    OutputFormat::Json => {
                        println!("{}", serde_json::to_string(&entries).unwrap_or_default());
                    }
                    OutputFormat::Quiet => {
                        for entry in &entries {
                            println!("{}", entry.id);
                        }
                    }
                    OutputFormat::Text => {
                        if entries.is_empty() {
                            println!("No progress entries for session {}.", session_id);
                        } else {
                            println!("Progress for session {} ({}):", session_id, entries.len());
                            println!();
                            for entry in &entries {
                                println!("[{}] {}", entry.created_at.format("%H:%M:%S"), entry.content);
                            }
                        }
                    }
                }
            } else {
                // List all with pagination
                let result = db::list_progress(&conn, cursor.as_deref(), Some(limit))?;

                match format {
                    OutputFormat::Json => {
                        println!("{}", serde_json::to_string(&result).unwrap_or_default());
                    }
                    OutputFormat::Quiet => {
                        for entry in &result.items {
                            println!("{}", entry.id);
                        }
                    }
                    OutputFormat::Text => {
                        if result.items.is_empty() {
                            println!("No progress entries found.");
                        } else {
                            for entry in &result.items {
                                println!("[{}] {}", entry.created_at.format("%Y-%m-%d %H:%M"), entry.content);
                            }
                            if result.has_next {
                                println!();
                                println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
                            }
                        }
                    }
                }
            }
        }

        ProgressCommands::Search { query, limit } => {
            // Use semantic search for relevance-ordered results
            let results = db::search_progress_semantic(&conn, &query, Some(limit))?;

            match format {
                OutputFormat::Json => {
                    // Extract just entries for JSON output
                    let entries: Vec<_> = results.iter().map(|(e, _)| e).collect();
                    println!("{}", serde_json::to_string(&entries).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for (entry, _) in &results {
                        println!("{}", entry.id);
                    }
                }
                OutputFormat::Text => {
                    if results.is_empty() {
                        println!("No progress entries found matching '{}'.", query);
                    } else {
                        println!("Found {} entry(ies) matching '{}' (ordered by relevance):", results.len(), query);
                        println!();
                        for (entry, distance) in &results {
                            let score = 1.0 - distance.min(1.0);
                            println!("[{} | {:.2}] {}", entry.created_at.format("%Y-%m-%d %H:%M"), score, entry.content);
                        }
                    }
                }
            }
        }
    }

    Ok(())
}

fn cmd_embeddings(project_dir: &PathBuf, command: EmbeddingsCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        EmbeddingsCommands::Status => {
            let stats = db::EmbeddingStats::collect(&conn)?;

            match format {
                OutputFormat::Json => {
                    println!(
                        r#"{{"task_embeddings":{},"progress_embeddings":{},"service_loaded":{}}}"#,
                        stats.task_embeddings,
                        stats.progress_embeddings,
                        stats.service_loaded
                    );
                }
                OutputFormat::Quiet => {
                    println!("{}/{}", stats.task_embeddings, stats.progress_embeddings);
                }
                OutputFormat::Text => {
                    println!("Embedding Statistics");
                    println!("====================");
                    println!();
                    println!("Task embeddings:     {}", stats.task_embeddings);
                    println!("Progress embeddings: {}", stats.progress_embeddings);
                    println!("Model loaded:        {}", if stats.service_loaded { "yes" } else { "no" });
                }
            }
        }

        EmbeddingsCommands::Rebuild { tasks_only, progress_only } => {
            let (tasks_count, progress_count) = if tasks_only {
                let count = db::rebuild_task_embeddings(&conn)?;
                (count, 0)
            } else if progress_only {
                let count = db::rebuild_progress_embeddings(&conn)?;
                (0, count)
            } else {
                let t = db::rebuild_task_embeddings(&conn)?;
                let p = db::rebuild_progress_embeddings(&conn)?;
                (t, p)
            };

            match format {
                OutputFormat::Json => {
                    println!(
                        r#"{{"tasks_rebuilt":{},"progress_rebuilt":{}}}"#,
                        tasks_count, progress_count
                    );
                }
                OutputFormat::Quiet => {
                    println!("{}/{}", tasks_count, progress_count);
                }
                OutputFormat::Text => {
                    println!("Embeddings rebuilt:");
                    println!("  Tasks:    {}", tasks_count);
                    println!("  Progress: {}", progress_count);
                }
            }
        }
    }

    Ok(())
}

